import React, { useState, useEffect } from "react";
import { Check, Download, RefreshCcw } from "lucide-react";
// Importe seu serviço/API conforme sua arquitetura

export default function BackupConfig() {
  // Estados principais
  const [autoBackup, setAutoBackup] = useState(false);
  const [periodicidade, setPeriodicidade] = useState("diario");
  const [destino, setDestino] = useState("google");
  const [limpezaAutomatica, setLimpezaAutomatica] = useState(true);
  const [backups, setBackups] = useState([]);
  const [carregando, setCarregando] = useState(true);

  // Ao montar, busque config e histórico (mock)
  useEffect(() => {
    // Buscar configs/histórico da API (mock de exemplo)
    setTimeout(() => {
      setAutoBackup(true);
      setPeriodicidade("diario");
      setDestino("google");
      setLimpezaAutomatica(true);
      setBackups([
        { nome: "backup_poliub_2024-08-10_03-00-00.zip", data: "2024-08-10 03:00", url: "/backups/backup1.zip" },
        { nome: "backup_poliub_2024-08-09_03-00-00.zip", data: "2024-08-09 03:00", url: "/backups/backup2.zip" },
      ]);
      setCarregando(false);
    }, 1000);
  }, []);

  function handleSalvar() {
    // Salvar configs (chame API backend)
    alert("Configurações de backup salvas!");
  }

  function handleBackupManual() {
    // Chamar endpoint de backup manual
    alert("Backup manual iniciado! (Simulação)");
  }

  function handleDownload(url) {
    window.open(url, "_blank");
  }

  return (
    <div className="max-w-2xl mx-auto py-8 px-4">
      <h2 className="text-2xl font-bold mb-6">Backup do Sistema</h2>
      <div className="bg-white rounded-2xl shadow p-6 space-y-5">

        {/* Ativar automático */}
        <div className="flex items-center gap-3">
          <input type="checkbox" id="autoBackup" checked={autoBackup} onChange={e => setAutoBackup(e.target.checked)} />
          <label htmlFor="autoBackup" className="font-medium">Ativar backup automático</label>
        </div>

        {/* Periodicidade */}
        <div className="flex gap-4 items-center">
          <span className="font-medium">Periodicidade:</span>
          <select className="border rounded px-2 py-1" value={periodicidade} onChange={e => setPeriodicidade(e.target.value)}>
            <option value="diario">Diário</option>
            <option value="semanal">Semanal</option>
          </select>
        </div>

        {/* Destino */}
        <div className="flex gap-4 items-center">
          <span className="font-medium">Destino:</span>
          <select className="border rounded px-2 py-1" value={destino} onChange={e => setDestino(e.target.value)}>
            <option value="google">Google Drive</option>
            <option value="dropbox">Dropbox</option>
          </select>
        </div>

        {/* Limpeza automática */}
        <div className="flex items-center gap-3">
          <input type="checkbox" id="limpezaAutomatica" checked={limpezaAutomatica} onChange={e => setLimpezaAutomatica(e.target.checked)} />
          <label htmlFor="limpezaAutomatica" className="font-medium">Limpeza automática (manter só 30 dias)</label>
        </div>

        {/* Botões principais */}
        <div className="flex gap-4 pt-4">
          <button
            onClick={handleSalvar}
            className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold px-4 py-2 rounded-full flex items-center gap-2"
          >
            <Check size={18} /> Salvar configurações
          </button>
          <button
            onClick={handleBackupManual}
            className="bg-green-600 hover:bg-green-700 text-white font-bold px-4 py-2 rounded-full flex items-center gap-2"
          >
            <RefreshCcw size={18} /> Fazer backup agora
          </button>
        </div>

        {/* Histórico de backups */}
        <div>
          <h3 className="font-semibold mb-2 mt-4">Histórico de Backups</h3>
          {carregando ? (
            <p className="text-gray-500">Carregando...</p>
          ) : (
            <ul className="divide-y divide-gray-200">
              {backups.map((b, i) => (
                <li key={i} className="flex items-center justify-between py-2">
                  <span>
                    <b>{b.nome}</b> <span className="text-xs text-gray-500 ml-2">{b.data}</span>
                  </span>
                  <button
                    onClick={() => handleDownload(b.url)}
                    className="text-blue-700 hover:underline flex items-center gap-1"
                  >
                    <Download size={16} /> Baixar
                  </button>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}
